def _title_case(s):
    if not s: return u''
    s = s.strip()
    _min = set([u'de', u'da', u'do', u'dos', u'das', u'e', u'o', u'a', u'os', u'as', u'em', u'na', u'no', u'nas', u'nos', u'por', u'para', u'com', u'sem'])
    out = []
    for i, w in enumerate(s.split()):
        if i > 0 and w.lower() in _min:
            out.append(w.lower())
        else:
            out.append(w.capitalize())
    return u' '.join(out)


def _fmt_cpf(s):
    if not s: return u''
    d = re.sub(r'\D', '', str(s))
    d = d[:11]
    if len(d) == 11:
        return u'{}.{}.{}-{}'.format(d[:3],d[3:6],d[6:9],d[9:])
    return str(s)


def _fmt_cnpj(s):
    if not s: return u''
    d = re.sub(r'\D', '', str(s))
    if len(d) == 14:
        return u'{}.{}.{}/{}-{}'.format(d[:2],d[2:5],d[5:8],d[8:12],d[12:])
    return str(s)


def _fmt_cep(s):
    if not s: return u''
    d = re.sub(r'\D', '', str(s))
    if len(d) == 8:
        return u'{}-{}'.format(d[:5],d[5:])
    return str(s)


def _fmt_tel(s):
    if not s: return u''
    s = str(s).strip()
    if not s: return u''
    d = re.sub(r'\D', '', s)
    if len(d) == 11:
        return u'({}) {}-{}'.format(d[:2],d[2:7],d[7:])
    if len(d) == 10:
        return u'({}) {}-{}'.format(d[:2],d[2:6],d[6:])
    return u''
