def maiusculo(v):
    return v if ('@' in v or 'http' in v) else v.upper()

def _badge_estado(estado):
    e = (estado or '').strip().lower()
    if e == 'bom':
        return VERDE_BG, VERDE_TX
    elif e == 'regular':
        return AMARELO_BG, AMARELO_TX
    else:
        return VERMELHO_BG, VERMELHO_TX

