def _build_person_blocos(persons, num_prefix, titulo_base):
    blocos = []
    for i, p in enumerate(persons):
        suffix = u' (%d)' % (i + 1) if len(persons) > 1 else ''
        blocos.append({
            'titulo': u'%s %s%s' % (num_prefix, titulo_base, suffix),
            'campos': [('Nome completo', p['nome']),
                       ('CPF', p['cpf'])] +
                      ([('RG', p['rg'])] if p.get('rg') else []) +
                      [('Telefone', p['telefone']),
                       ('E-mail', p['email'])],
            'is_imob': False
        })
    return blocos


def add_partes_cards(story, s, blocos):
    """Partes em 2 colunas separadas por linha vertical fina."""
    story.append(Paragraph(u'Partes Envolvidas', s['sub']))
    GAP = 8
    CW  = (TW - GAP) / 2

    for i in range(0, len(blocos), 2):
        par = blocos[i:i+2]
        linhas_e = _parte_col(par[0]['titulo'], par[0]['campos'], s)
        if len(par) > 1:
            linhas_d = _parte_col(par[1]['titulo'], par[1]['campos'], s)
        else:
            linhas_d = [[Spacer(1,1)]]

        max_r = max(len(linhas_e), len(linhas_d))
        while len(linhas_e) < max_r: linhas_e.append([Spacer(1,1)])
        while len(linhas_d) < max_r: linhas_d.append([Spacer(1,1)])

        rows = [[linhas_e[r][0], linhas_d[r][0]] for r in range(max_r)]

        t = Table(rows, colWidths=[CW, CW], spaceAfter=6)
        styles_t = [
            ('VALIGN',       (0,0), (-1,-1), 'TOP'),
            ('LEFTPADDING',  (0,0), (-1,-1), 0),
            ('RIGHTPADDING', (0,0), (0,-1),  GAP),
            ('RIGHTPADDING', (1,0), (1,-1),  0),
            ('TOPPADDING',   (0,0), (-1,-1), 2),
            ('BOTTOMPADDING',(0,0), (-1,-1), 1),
            ('LINEAFTER',    (0,0), (0,-1),  0.5, HexColor('#ebebeb')),
            ('LEFTPADDING',  (1,0), (1,-1),  GAP),
        ]
        t.setStyle(TableStyle(styles_t))
        story.append(t)

def add_card_imob_corretor(story, s, dados_imobiliaria, dados_corretor):
    """Card Imobiliaria/Corretor com layout 2 colunas lado a lado."""
    story.append(Paragraph(u'Partes Envolvidas', s['sub']))

    has_imob = bool(dados_imobiliaria and dados_imobiliaria.get('nome'))

    corr_nome  = dados_corretor.get('nome',  u'芒聙聰') or u'芒聙聰'
    corr_creci = dados_corretor.get('creci', u'芒聙聰') or u'芒聙聰'
    corr_tel   = dados_corretor.get('telefone', u'') or u''
    corr_email = dados_corretor.get('email', u'芒聙聰') or u'芒聙聰'

    def _build_block(title, campos):
        inner_rows = [[Paragraph(title, s['parte_titulo'])]]
        for lbl, val, style_key in campos:
            inner_rows.append([Paragraph(lbl, s['parte_label'])])
            inner_rows.append([Paragraph(val, s[style_key])])
        inner_t = Table(inner_rows, colWidths=[None])
        inner_t.setStyle(TableStyle([
            ('LEFTPADDING',  (0,0), (-1,-1), 0),
            ('RIGHTPADDING', (0,0), (-1,-1), 0),
            ('TOPPADDING',   (0,0), (-1,-1), 2),
            ('BOTTOMPADDING',(0,0), (-1,-1), 1),
            ('LINEBELOW', (0,0), (0,0), 0.5, HexColor('#ddeeff')),
        ]))
        return inner_t

    if has_imob:
        imob_nome  = dados_imobiliaria.get('nome', u'芒聙聰') or u'芒聙聰'
        imob_cnpj  = dados_imobiliaria.get('cnpj', u'芒聙聰') or u'芒聙聰'
        imob_tel   = dados_imobiliaria.get('telefone', u'芒聙聰') or u'芒聙聰'
        imob_email = dados_imobiliaria.get('email', u'芒聙聰') or u'芒聙聰'

        left_block = _build_block(u'Imobili\u00e1ria', [
            ('NOME',     imob_nome,             'parte_valor'),
            ('CNPJ',     imob_cnpj,             'parte_valor'),
            ('TELEFONE', imob_tel,              'parte_valor'),
            ('E-MAIL',   imob_email,            'parte_email'),
        ])
        right_block = _build_block(u'Corretor', [
            ('NOME',     corr_nome,             'parte_valor'),
            ('CRECI',    maiusculo(corr_creci), 'parte_valor'),
            ('TELEFONE', corr_tel or u'芒聙聰', 'parte_valor'),
            ('E-MAIL',   corr_email,            'parte_email'),
        ])

        half = (TW - 10) / 2
        outer = Table([[left_block, right_block]], colWidths=[half, half], spaceAfter=6)
        outer.setStyle(TableStyle([
            ('LEFTPADDING',  (0,0), (-1,-1), 0),
            ('RIGHTPADDING', (0,0), (-1,-1), 0),
            ('TOPPADDING',   (0,0), (-1,-1), 0),
            ('BOTTOMPADDING',(0,0), (-1,-1), 0),
            ('VALIGN',       (0,0), (-1,-1), 'TOP'),
        ]))
        story.append(outer)
    else:
        linhas = [[Paragraph(u'Imobili\u00e1ria / Corretor', s['parte_titulo'])]]
        linhas.append([Paragraph('NOME', s['parte_label'])])
        linhas.append([Paragraph(corr_nome, s['parte_valor'])])
        linhas.append([Paragraph('CRECI', s['parte_label'])])
        linhas.append([Paragraph(maiusculo(corr_creci), s['parte_valor'])])
        linhas.append([Paragraph('E-MAIL', s['parte_label'])])
        linhas.append([Paragraph(corr_email, s['parte_email'])])
        t = Table(linhas, colWidths=[TW], spaceAfter=6)
        t.setStyle(TableStyle([
            ('LEFTPADDING',  (0,0), (-1,-1), 0),
            ('RIGHTPADDING', (0,0), (-1,-1), 0),
            ('TOPPADDING',   (0,0), (-1,-1), 2),
            ('BOTTOMPADDING',(0,0), (-1,-1), 1),
            ('LINEBELOW', (0,0), (0,0), 0.5, HexColor('#ddeeff')),
        ]))
        story.append(t)

def add_foto_item(story, s, item, numero_inicio=1):
    """Renders only the photos with numbers (no description, no badge)."""
    fotos = item.get('fotos', [])

    for i, foto_bytes in enumerate(fotos):
        n = numero_inicio + i
        try:
            img = Image(io.BytesIO(foto_bytes), width=FOTO_W, height=FOTO_H)
            img.hAlign = 'LEFT'
            conteudo = [
                [Paragraph(f'Foto {n}', s['foto_num'])],
                [img],
            ]
            bloco = Table(conteudo, colWidths=[TW])
            bloco.setStyle(TableStyle([
                ('BOX',           (0,0), (-1,-1), 0.5, CINZA_AMB),
                ('BACKGROUND',    (0,0), (-1,-1), HexColor('#fafafa')),
                ('LEFTPADDING',   (0,0), (-1,-1), 8),
                ('RIGHTPADDING',  (0,0), (-1,-1), 8),
                ('TOPPADDING',    (0,0), (0,0),   3),
                ('BOTTOMPADDING', (-1,0),(-1,-1), 2),
            ]))
            story.append(Spacer(1, 5))
            story.append(KeepTogether([bloco]))
        except Exception:
            story.append(Paragraph(
                f'[Foto {n} \u2014 imagem n\u00e3o dispon\u00edvel]',
                s['foto_desc']))

    story.append(Spacer(1, 3))
def add_ambientes(story, s, ambientes):
    story.append(CondPageBreak(inch * 5))
    add_parte(story, s, u'Parte 2 \u2014 Vistoria dos Ambientes')

    if not ambientes:
        story.append(Paragraph(
            u'[ Ambientes, fotos numeradas, descri\u00e7\u00f5es geradas pela IA izyLAUDO '
            u'e verifica\u00e7\u00f5es t\u00e9cnicas inseridos automaticamente ]',
            s['vistoria_box']))
        return

    for amb in ambientes:
        foto_global = 1  # Reinicia numeracao por ambiente
        # Garante espa脙搂o m脙颅nimo antes do t脙颅tulo (evita t脙颅tulo grudado no final da p脙隆gina)
        story.append(CondPageBreak(3.5*cm))
        # Nome do ambiente com linha abaixo bold - KeepTogether garante que titulo + HR + primeiro item fiquem juntos
        titulo_block = []
        titulo_block.append(Paragraph(amb['nome'].upper(), s['ambiente_titulo']))
        titulo_block.append(HRFlowable(width='100%', thickness=1.5, color=PRETO,
                                spaceBefore=0, spaceAfter=4))
        story.append(KeepTogether(titulo_block))

        for item in amb.get('itens', []):
            add_foto_item(story, s, item, foto_global)
            foto_global += len(item.get('fotos', [])) or 1


        # === SINTESE / CONCLUSAO FINAL DO AMBIENTE ===
        # Collect description from items
        desc_ambiente = ''
        for item in amb.get('itens', []):
            d = item.get('descricao_ia', '')
            if d and not desc_ambiente:
                desc_ambiente = d

        # Extract estado from AI description text (reliable source)
        estado_ambiente = 'Bom'
        if desc_ambiente:
            import re
            _dl = desc_ambiente.lower()
            # Look for exact matches: "com avaria", "regular", or "bom" right after "estado geral"
            if re.search(r'estado\s*geral[^a-z]*(com\s+avaria)', _dl):
                estado_ambiente = 'Com avaria'
            elif re.search(r'estado\s*geral[^a-z]*(regular)', _dl):
                estado_ambiente = 'Regular'
            elif re.search(r'estado\s*geral[^a-z]*(bom)', _dl):
                estado_ambiente = 'Bom'

        if desc_ambiente:
            import re as _re
            # --- Title + intro kept together so they don't split across pages ---
            _header_parts = [
                Spacer(1, 6),
                HRFlowable(width='100%', thickness=0.5, color=HexColor('#cccccc'),
                           spaceBefore=2, spaceAfter=4),
                Paragraph(
                    f'\u2726 CONCLUS\u00c3O \u2014 {amb["nome"].upper()}',
                    s['conclusao_titulo']),
                Paragraph(
                    f'A presente conclus\u00e3o baseia-se nas condi\u00e7\u00f5es gerais do ambiente <b>{amb["nome"]}</b>, '
                    f'conforme registrado nas fotos acima.',
                    s['conclusao_texto']),
            ]
            story.append(KeepTogether(_header_parts))

            # --- Split synthesis into separate paragraphs per category ---
            _categorias = [
                'S\u00cdNTESE DO AMBIENTE',
                'Piso', 'Paredes', 'Teto', 'Esquadrias',
                'Instala\u00e7\u00f5es', 'M\u00f3veis e equipamentos',
                'Observa\u00e7\u00f5es', 'Estado geral'
            ]
            _cat_pattern = '(' + '|'.join(_re.escape(cat) for cat in _categorias) + r')\s*:'
            _seg = _re.split(_cat_pattern, desc_ambiente)
            if len(_seg) > 2:
                # _seg = [before, cat1, text1, cat2, text2, ...]
                if _seg[0].strip():
                    story.append(Paragraph(_seg[0].strip(), s['conclusao_texto']))
                for _j in range(1, len(_seg) - 1, 2):
                    _cat_name = _seg[_j].strip()
                    _cat_text = _seg[_j + 1].strip() if _j + 1 < len(_seg) else ''
                    story.append(Paragraph(
                        f'<b>{_cat_name}:</b> {_cat_text}',
                        s['conclusao_texto']))
            else:
                # Fallback: no known categories found, render as single block
                story.append(Paragraph(desc_ambiente, s['conclusao_texto']))

            # --- Color-coded avaliacao ---
            if estado_ambiente:
                # Color-coded: green=Bom, yellow=Regular, red=Com avaria
                _cor_mapa = {
                    'Bom': HexColor('#008800'),
                    'Regular': HexColor('#CC8800'),
                    'Com avaria': HexColor('#CC0000'),
                }
                _cor_estado = _cor_mapa.get(estado_ambiente, HexColor('#CC0000'))
                _estilo_estado = ParagraphStyle('estado_dyn',
                    fontName='Helvetica-Bold', fontSize=10, textColor=_cor_estado,
                    leading=14, spaceBefore=4, spaceAfter=6)
                story.append(Paragraph(
                    f'AVALIA\u00c7\u00c3O: {estado_ambiente.upper()}',
                    _estilo_estado))

        verif = amb.get('verificacoes', {})
        if verif:
            story.append(Spacer(1, 4))
            story.append(Paragraph(u'Verifica\u00e7\u00f5es T\u00e9cnicas', s['secao']))
            mapa = {
                'iluminacao'    : u'Ilumina\u00e7\u00e3o',
                'tomadas'       : 'Tomadas',
                'agua'          : u'\u00c1gua / Encanamento',
                'ar_condicionado': 'Ar-condicionado',
                'portas'        : 'Portas / Fechaduras',
            }
            verif_obs = amb.get('verificacoes_obs', {}) or {}
            linhas = []
            obs_rows = []
            testes_nomes = amb.get('testes_nomes', {})
            for k, v in verif.items():
                if k.endswith('_obs'):
                    continue
                label = mapa.get(k, testes_nomes.get(k, k.replace('_', ' ').capitalize()))
                linhas.append([
                    Paragraph(label, s['verif_label']),
                    Paragraph(f'<b>{v}</b>', s['verif_label']),
                ])
                obs_txt = verif_obs.get(k, '') or verif.get(k + '_obs', '') or ''
                if obs_txt:
                    obs_esc = str(obs_txt).replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;')
                    obs_rows.append(len(linhas))
                    linhas.append([
                        Paragraph(f'<font color="#64748b" size="7"><i>Obs.: {obs_esc}</i></font>', s['verif_label']),
                        Paragraph('', s['verif_label']),
                    ])
            if linhas:
                t = Table(linhas, colWidths=[TW*0.6, TW*0.4])
                _vstyle = [
                    ('FONTSIZE',    (0,0), (-1,-1), 8),
                    ('TOPPADDING',  (0,0), (-1,-1), 3),
                    ('BOTTOMPADDING',(0,0),(-1,-1), 3),
                    ('LINEBELOW',   (0,0), (-1,-2), 0.3, CINZA),
                    ('LEFTPADDING', (0,0), (-1,-1), 0),
                ]
                for _or in obs_rows:
                    _vstyle.append(('SPAN', (0, _or), (-1, _or)))
                    _vstyle.append(('LEFTPADDING', (0, _or), (-1, _or), 12))
                    _vstyle.append(('TOPPADDING', (0, _or), (-1, _or), 0))
                    _vstyle.append(('BOTTOMPADDING', (0, _or), (-1, _or), 2))
                t.setStyle(TableStyle(_vstyle))
                story.append(t)

        obs_g = amb.get('observacoes_gerais', '')
        if obs_g:
            story.append(Spacer(1, 4))
            story.append(Paragraph(u'Observa\u00e7\u00e3o geral', s['secao']))
            story.append(Paragraph(obs_g, s['obs']))

        # Inventario (apenas temporada)
        _inventario = amb.get('inventario', {}) or {}
        _inv_nomes  = amb.get('inventarioNomes', []) or []
        _inv_extras = amb.get('inventarioExtras', []) or []
        # Se n茫o tem nomes mas tem invent谩rio, extrair nomes das chaves
        if _inventario and not _inv_nomes:
            _inv_nomes_auto = set()
            for _k in _inventario.keys():
                for _suf in ['_qty','_estado','_obs']:
                    if _k.endswith(_suf):
                        _inv_nomes_auto.add(_k[:-len(_suf)])
            _inv_nomes = list(_inv_nomes_auto)
        _todos = list(_inv_nomes) + list(_inv_extras)
        # Renderizar se tem qualquer dado
        _linhas = []
        for _item in _todos:
            _key = re.sub(r'[\s\/\(\)\.]+', '_', str(_item)).lower()
            _estado = _inventario.get(_key + '_estado', '')
            _qty    = _inventario.get(_key + '_qty', 0)
            _obs    = _inventario.get(_key + '_obs', '') or u''

            if not _estado and (not _qty or int(str(_qty)) == 0) and not _obs:
                continue

            _label = (u'\u2713 Bom'    if _estado == 'bom'
                      else u'\u26a0 Avaria'  if _estado == 'avaria'
                      else u'\u2717 Ausente' if _estado == 'ausente'
                      else u'\u2014')
            _linhas.append([str(_item), str(_qty or 0), _label, _obs])
        if _linhas:
            story.append(Spacer(1, 8))
            story.append(Paragraph(u'Invent谩rio do ambiente', s['secao']))
            _dados = [[u'Item', u'Qtd', u'Estado', u'Observa莽茫o']] + _linhas
            _t = Table(_dados, colWidths=[180, 30, 70, 180])
            _t.setStyle(TableStyle([
                ('FONTNAME',     (0,0),(-1,0),   'Helvetica-Bold'),
                ('FONTSIZE',     (0,0),(-1,-1),  8),
                ('BACKGROUND',   (0,0),(-1,0),   HexColor('#dbeafe')),
                ('TEXTCOLOR',    (0,0),(-1,0),   HexColor('#1e3a5f')),
                ('GRID',         (0,0),(-1,-1),  0.3, HexColor('#93c5fd')),
                ('ROWBACKGROUNDS',(0,1),(-1,-1), [colors.white, HexColor('#eff6ff')]),
                ('VALIGN',       (0,0),(-1,-1),  'MIDDLE'),
                ('TOPPADDING',   (0,0),(-1,-1),  4),
                ('BOTTOMPADDING',(0,0),(-1,-1),  4),
            ]))
            story.append(_t)
            story.append(Spacer(1, 6))

        story.append(Spacer(1, 5))

def add_assinaturas(story, s, partes, local_data):
    add_parte(story, s, u'Parte 4 \u2014 Declara\u00e7\u00e3o e Assinaturas')
    story.append(Paragraph(
        u'As partes declaram ter lido e compreendido integralmente este laudo, '
        u'concordando com os registros fotogr\u00e1ficos, descri\u00e7\u00f5es e estados de '
        u'conserva\u00e7\u00e3o nele contidos, cientes de que este documento \u00e9 <b>parte '
        u'integrante do contrato de loca\u00e7\u00e3o</b> em vigor.', s['normal']))
    story.append(Paragraph(f'Local e data: {local_data}', s['data']))

    # Assinaturas em grid 2 colunas
    for i in range(0, len(partes), 2):
        par = partes[i:i+2]
        cells = []
        for nome, papel, cpf in par:
            cells.append([
                HRFlowable(width='65%', thickness=0.8, color=PRETO,
                           spaceBefore=20, spaceAfter=3),
                Paragraph(f'<b>{nome.upper()}</b>', s['assinatura']),
                Paragraph(f'{papel} \u00b7 CPF: {cpf}', s['assinatura']),
            ])
        if len(cells) == 1:
            cells.append([Spacer(1,1)])
        row = Table([[cells[0], cells[1]]], colWidths=[TW/2, TW/2])
        row.setStyle(TableStyle([
            ('VALIGN',      (0,0),(-1,-1),'TOP'),
            ('LEFTPADDING', (0,0),(-1,-1),0),
            ('RIGHTPADDING',(0,0),(-1,-1),0),
            ('TOPPADDING',  (0,0),(-1,-1),0),
            ('BOTTOMPADDING',(0,0),(-1,-1),0),
        ]))
        story.append(row)

