def generate_pdf(inspection_data: dict, rooms_data: list,
                 signatures_data: list, output_path: str) -> bool:
    """
    Gera o Laudo de Vistoria em PDF.
    Assinatura compat\u00edvel com GeneratePDFHandler em server.py.
    """
    try:
        insp = inspection_data

        address = _safe(insp.get('property_address'))
        inspection_date_str = _safe(insp.get('inspection_date'), '')
        dt = _parse_date(inspection_date_str)
        date_display = _format_date_display(inspection_date_str)

        cidade_raw = _safe(insp.get('cidade'), '')
        estado_raw = _safe(insp.get('estado'), '')
        # Fallback: se estado vazio e cidade tem "Cidade / UF" num campo unico, fazer split
        if cidade_raw and not estado_raw:
            for _sep in (' / ', '/', ' - ', ','):
                if _sep in cidade_raw:
                    _p = cidade_raw.rsplit(_sep, 1)
                    if len(_p) == 2 and 2 <= len(_p[1].strip()) <= 3:
                        cidade_raw = _p[0].strip()
                        estado_raw = _p[1].strip().upper()
                        break
        if cidade_raw and estado_raw:
            cidade_uf = u'{} / {}'.format(cidade_raw, estado_raw)
        elif cidade_raw:
            cidade_uf = cidade_raw
        elif estado_raw:
            cidade_uf = estado_raw
        else:
            cidade_uf = u'\u2014'

        _end = _safe(insp.get('address') or insp.get('endereco'), u'')
        _num = _safe(insp.get('number') or insp.get('numero'), u'')
        _end_completo = (_end + (u', ' + _num if _num else u'')).strip()
        dados_imovel = {
            'endereco'    : _title_case(_end_completo),
            'complemento' : _title_case(_safe(insp.get('complemento'), u'\u2014')),
            'bairro'      : _title_case(_safe(insp.get('bairro'), u'\u2014')),
            'cidade_uf'   : _title_case(cidade_uf),
            'cep'         : _fmt_cep(_safe(insp.get('cep'), u'\u2014')),
            'tipo'        : _title_case(_safe(insp.get('property_type'), u'\u2014')),
            'area'        : _safe(insp.get('property_area'), u'\u2014'),
            'data_hora'   : date_display,
            'numero_laudo': _generate_numero_laudo(insp),
        }

        # --- Locadores (lista) ---
        locadores_raw = insp.get('locadores_json', '')
        try:
            locadores_list = json.loads(locadores_raw) if locadores_raw else []
        except Exception as e:
            locadores_list = []
        if not locadores_list:
            locadores_list = [{'name': insp.get('locador_name', ''),
                               'cpf': insp.get('locador_cpf', ''),
                               'rg': insp.get('locador_rg', ''),
                               'phone': insp.get('locador_phone', ''),
                               'email': insp.get('locador_email', '')}]
        locadores = [{'nome': _title_case(_safe(loc.get('name', ''), u'\u2014')),
                      'cpf': _fmt_cpf(_safe(loc.get('cpf', ''), u'\u2014')),
                      'rg': _safe(loc.get('rg', ''), ''),
                      'telefone': _fmt_tel(_safe(loc.get('phone', ''), u'\u2014')),
                      'email': (_safe(loc.get('email', ''), u'\u2014') or '').lower().strip()} for loc in locadores_list]
        dados_locador = locadores[0]

        # --- Locatarios (lista) ---
        locatarios_raw = insp.get('locatarios_json', '')
        try:
            locatarios_list = json.loads(locatarios_raw) if locatarios_raw else []
        except Exception as e:
            locatarios_list = []
        if not locatarios_list:
            locatarios_list = [{'name': insp.get('locatario_name', ''),
                               'cpf': insp.get('locatario_cpf', ''),
                               'rg': insp.get('locatario_rg', ''),
                               'phone': insp.get('locatario_phone', ''),
                               'email': insp.get('locatario_email', '')}]
        locatarios = [{'nome': _title_case(_safe(loc.get('name', ''), u'\u2014')),
                       'cpf': _fmt_cpf(_safe(loc.get('cpf', ''), u'\u2014')),
                       'rg': _safe(loc.get('rg', ''), ''),
                       'telefone': _fmt_tel(_safe(loc.get('phone', ''), u'\u2014')),
                       'email': (_safe(loc.get('email', ''), u'\u2014') or '').lower().strip()} for loc in locatarios_list]
        dados_locatario = locatarios[0]

        dados_corretor = {
            'nome'     : _title_case(_safe(insp.get('corretor_name'), '')),
            'creci'    : _safe(insp.get('corretor_creci'), ''),
            'telefone' : _fmt_tel(_safe(insp.get('corretor_phone'), '')),
            'email'    : (_safe(insp.get('corretor_email'), '') or '').lower().strip(),
        }

        dados_imobiliaria = {
            'nome'     : _title_case(_safe(insp.get('imobiliaria_name'), '')),
            'cnpj'     : _fmt_cnpj(_safe(insp.get('imobiliaria_cnpj'), '')),
            'telefone' : _fmt_tel(_safe(insp.get('imobiliaria_phone'), '')),
            'endereco' : _title_case(_safe(insp.get('imobiliaria_address'), '')),
            'email'    : (_safe(insp.get('imobiliaria_email'), '') or '').lower().strip(),
        }

        amb_json = insp.get('ambientes_json', '')
        if amb_json:
            ambientes = _build_ambientes_from_json(amb_json)
            # Overlay POST data by index (order is always consistent)
            for i, amb in enumerate(ambientes):
                if i < len(rooms_data):
                    r = rooms_data[i]
                    if r.get('verificacoes'):
                        amb['verificacoes'] = r['verificacoes']
                    if r.get('verificacoes_obs'):
                        amb['verificacoes_obs'] = r['verificacoes_obs']
                    if r.get('testes_nomes'):
                        amb['testes_nomes'] = r.get('testes_nomes', {})
                    obs = _safe(r.get('observacoes', r.get('observations', '')), '')
                    if obs:
                        amb['observacoes_gerais'] = obs
                    if r.get('inventario'):
                        amb['inventario'] = r.get('inventario', {}) or {}
                    if r.get('inventarioNomes'):
                        amb['inventarioNomes'] = r.get('inventarioNomes', []) or []
                    if r.get('inventarioExtras'):
                        amb['inventarioExtras'] = r.get('inventarioExtras', []) or []
        else:
            ambientes = _build_ambientes(rooms_data)

        # === Suite sub-ambientes expansion ===
        _expanded = []
        for _i, _amb in enumerate(ambientes):
            _rd = rooms_data[_i] if _i < len(rooms_data) else {}
            if _rd.get('subAmbientes'):
                _suite_name = _amb['nome']
                # Build photo lookup from original ambientes_json itens by sub-ambiente name
                _foto_lookup = {}
                for _orig_item in _amb.get('itens', []):
                    _item_nome = _orig_item.get('nome', '')
                    if _item_nome not in _foto_lookup:
                        _foto_lookup[_item_nome] = []
                    _foto_lookup[_item_nome].extend(_orig_item.get('fotos', []))
                # For non-suites, keep the main room with its own photos
                if not _rd.get('isSuite'):
                    _main_amb = dict(_amb)
                    _main_amb['itens'] = [_oi for _oi in _amb.get('itens', []) if _oi.get('nome', '') == _suite_name]
                    if not _main_amb['itens']:
                        _main_fotos = _foto_lookup.get(_suite_name, [])
                        for _fi, _fb in enumerate(_main_fotos):
                            _main_amb['itens'].append({'nome': _suite_name, 'estado': '', 'descricao_ia': '', 'observacao': '', 'fotos': [_fb] if _fb else []})
                    _main_amb['verificacoes'] = _rd.get('verificacoes', {})
                    _main_amb['verificacoes_obs'] = _rd.get('verificacoesObs', {})
                    _main_amb['testes_nomes'] = _rd.get('testesNomes', {})
                    _main_amb['observacoes_gerais'] = _safe(_rd.get('observacoes', ''), '')
                    _expanded.append(_main_amb)
                for _sub in _rd['subAmbientes']:
                    _sub_nome = _sub.get('nome', '')
                    _resumo = _sub.get('resumo', '')
                    # Get photos for this sub-ambiente from the original ambientes_json data
                    _sub_fotos = _foto_lookup.get(_sub_nome, [])
                    _sub_display = f'{_sub_nome} ({_suite_name})' if not _rd.get('isSuite') else f'{_suite_name} \u2014 {_sub_nome}'
                    # Build itens from photos
                    _sub_itens = []
                    if _sub_fotos:
                        for _fi, _fb in enumerate(_sub_fotos):
                            _sub_itens.append({
                                'nome': _sub_nome,
                                'estado': '',
                                'descricao_ia': _resumo if _fi == 0 else '',
                                'observacao': '',
                                'fotos': [_fb] if _fb else [],
                            })
                    # Ensure resumo is always present even without photos
                    if not _sub_itens and _resumo:
                        _sub_itens = [{'nome': _sub_nome, 'estado': '', 'descricao_ia': _resumo, 'observacao': '', 'fotos': []}]
                    elif _sub_itens and _resumo and not _sub_itens[0].get('descricao_ia'):
                        _sub_itens[0]['descricao_ia'] = _resumo
                    _sub_amb = {
                        'nome': _sub_display,
                        'itens': _sub_itens,
                        'verificacoes': _sub.get('verificacoes', {}),
                        'verificacoes_obs': _sub.get('verificacoesObs', {}),
                        'testes_nomes': _sub.get('testesNomes', {}),
                        'observacoes_gerais': _safe(_sub.get('observacoes', ''), ''),
                    }
                    _expanded.append(_sub_amb)
            else:
                _expanded.append(_amb)
        ambientes = _expanded

        local_data = _format_date_extenso(dt)
        if cidade_raw:
            local_data = f'{cidade_raw}, {local_data}'

        # ---- Selecao do modelo baseado em tipo x responsavel ----
        tipo = _safe(insp.get('type', 'entrada')).lower().strip()
        responsavel = _safe(insp.get('responsavel', 'proprietario')).lower().strip()

        args = (dados_imovel, dados_locador, dados_locatario,
                dados_corretor, dados_imobiliaria,
                ambientes, local_data, output_path,
                locadores, locatarios)

        if tipo == 'entrada' and responsavel == 'imobiliaria':
            gerar_laudo_modelo1(*args)
        elif tipo == 'entrada':
            gerar_laudo_modelo2(*args)
        elif tipo == 'saida' and responsavel == 'imobiliaria':
            gerar_laudo_modelo3(*args)
        elif tipo == 'saida':
            gerar_laudo_modelo4(*args)
        elif tipo == 'temporada' and responsavel == 'imobiliaria':
            gerar_laudo_modelo5(*args)
        elif tipo == 'temporada':
            gerar_laudo_modelo6(*args)
        else:
            gerar_laudo_modelo2(*args)  # fallback

        logger.info(f'PDF gerado com sucesso: {output_path}')
        return True

    except Exception as e:
        logger.error(f'Erro ao gerar PDF: {e}', exc_info=True)
        return False
